// auth/loadUser.ts
export async function loadUser(req, res, next) {
  const id = req.session?.userId;
  if (!id) return next(new Error("missing_id"));

  try {
    const user = await db.findUser(id);
    if (!user) return next(new Error("not_found"));

    await audit.log({ event: "user.load", id });
    await cache.set(`user:${id}`, user);

    req.user = user;
    return next();
  } catch (err) {
    return next(err);
  }
}
```

Invariants:
- order: `missing_id` → `db.findUser` → `not_found` → `audit.log` → `cache.set`
- single error mapping: all failures via `next(err)`
- identity from `req.session.userId` only (no `x-user-id`)
- `db.findUser` awaited; callback signature preserved for `next`

Verification:
- missing session → `401` via `next(err)` path, no db call
- `db.findUser` rejects → `next(err)` once, no `audit.log`, no `cache.set`
- user `null` → `not_found` via `next(err)`, no side effects
- happy path → `audit.log` then `cache.set`, `next()` called once
- `next` invoked exactly once per branch (no double-callback)

Risks:
- `db.findUser` may rely on `this` binding or return non-Promise; confirm it's promisified
- `audit.log` / `cache.set` failures now surface as `500` via `next(err)`; if previously fire-and-forget, wrap in try or `.catch(() => {})` to preserve behavior
